import{_ as t,o as i,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Find Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Dateisuche optimieren mit fd-basierten Aliasen. Schnelle, farbige Ausgabe und intuitive Befehle fuer Unix-Systeme.","frontmatter":{"title":"Find Aliase | Dotfiles","description":"Dateisuche optimieren mit fd-basierten Aliasen. Schnelle, farbige Ausgabe und intuitive Befehle fuer Unix-Systeme.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Find Aliase preview","canonical":"/de/aliases/find/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Find Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Find Aliase - Dotfiles (DE)","permalink":"/de/aliases/find/","sidebar":true,"meta":[{"name":"keywords","content":"find aliase, fd befehl, dateisuche, shell aliase, dotfiles, unix find"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Find Aliase - Dotfiles"},{"name":"twitter:description","content":"Dateisuche optimieren mit fd-basierten Aliasen. Schnelle, farbige Ausgabe und intuitive Befehle."},{"name":"og:title","content":"Find Aliase - Dotfiles"},{"name":"og:description","content":"Dateisuche optimieren mit fd-basierten Aliasen. Schnelle, farbige Ausgabe und intuitive Befehle."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/find/index.md","filePath":"de/aliases/find/index.md","lastUpdated":1773010926000}'),a={name:"de/aliases/find/index.md"};function n(s,e,o,r,f,c){return i(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="find-aliase" tabindex="-1">Find Aliase <a class="header-anchor" href="#find-aliase" aria-label="Permalink to &quot;Find Aliase&quot;">​</a></h1><p>Leistungsstarke Dateisuche-Verknuepfungen mit fd, der modernen Alternative zu find.</p><h2 id="uebersicht" tabindex="-1">Uebersicht <a class="header-anchor" href="#uebersicht" aria-label="Permalink to &quot;Uebersicht&quot;">​</a></h2><p>Diese Aliase bieten eine optimierte Schnittstelle zu <code>fd</code>, einer schnellen und benutzerfreundlichen Alternative zum traditionellen <code>find</code>-Befehl. In <code>find.aliases.sh</code> definiert, werden sie automatisch von Chezmoi geladen und bieten farbige Ausgabe, intuitive Syntax und einpraegsame Befehle fuer gaengige Dateisuchoperationen.</p><p>Wenn <code>fd</code> auf Ihrem System verfuegbar ist, wird der <code>find</code>-Befehl automatisch als Alias fuer <code>fd</code> gesetzt, was Ihnen verbesserte Leistung und eine einfachere Syntax standardmaessig bietet.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="kernbefehle" tabindex="-1">Kernbefehle <a class="header-anchor" href="#kernbefehle" aria-label="Permalink to &quot;Kernbefehle&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>fd</code></td><td style="text-align:left;"><code>fd --color always</code></td><td style="text-align:left;">Dateien mit farbiger Ausgabe suchen</td></tr><tr><td style="text-align:left;"><code>find</code></td><td style="text-align:left;"><code>fd</code></td><td style="text-align:left;">fd als Standard-find-Ersatz verwenden</td></tr></tbody></table><h3 id="suchoptionen" tabindex="-1">Suchoptionen <a class="header-anchor" href="#suchoptionen" aria-label="Permalink to &quot;Suchoptionen&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>fda</code></td><td style="text-align:left;"><code>fd --absolute-path</code></td><td style="text-align:left;">Ergebnisse mit absoluten Pfaden anzeigen</td></tr><tr><td style="text-align:left;"><code>fdc</code></td><td style="text-align:left;"><code>fd --ignore-case</code></td><td style="text-align:left;">Gross-/Kleinschreibung ignorieren</td></tr><tr><td style="text-align:left;"><code>fdd</code></td><td style="text-align:left;"><code>fd --list-details</code></td><td style="text-align:left;">Detaillierte Dateiinformationen anzeigen</td></tr><tr><td style="text-align:left;"><code>fde</code></td><td style="text-align:left;"><code>fd --extension</code></td><td style="text-align:left;">Nach Dateierweiterung filtern</td></tr><tr><td style="text-align:left;"><code>fdf</code></td><td style="text-align:left;"><code>fd --follow</code></td><td style="text-align:left;">Symbolischen Links bei Suche folgen</td></tr><tr><td style="text-align:left;"><code>fdh</code></td><td style="text-align:left;"><code>fd --hidden</code></td><td style="text-align:left;">Versteckte Dateien in Ergebnissen einschliessen</td></tr><tr><td style="text-align:left;"><code>fdn</code></td><td style="text-align:left;"><code>fd --glob</code></td><td style="text-align:left;">Dateien mit Glob-Mustern abgleichen</td></tr><tr><td style="text-align:left;"><code>fdo</code></td><td style="text-align:left;"><code>fd --owner</code></td><td style="text-align:left;">Nach Dateieigentuemer filtern</td></tr><tr><td style="text-align:left;"><code>fds</code></td><td style="text-align:left;"><code>fd --size</code></td><td style="text-align:left;">Nach Dateigroesse filtern</td></tr><tr><td style="text-align:left;"><code>fdu</code></td><td style="text-align:left;"><code>fd --exclude</code></td><td style="text-align:left;">Dateien ausschliessen, die einem Muster entsprechen</td></tr><tr><td style="text-align:left;"><code>fdx</code></td><td style="text-align:left;"><code>fd --exec</code></td><td style="text-align:left;">Befehl fuer jedes Ergebnis ausfuehren</td></tr></tbody></table><h3 id="hilfsbefehle" tabindex="-1">Hilfsbefehle <a class="header-anchor" href="#hilfsbefehle" aria-label="Permalink to &quot;Hilfsbefehle&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Befehl</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>fdv</code></td><td style="text-align:left;"><code>fd --version</code></td><td style="text-align:left;">fd-Versionsinformationen anzeigen</td></tr></tbody></table>',12)])])}const u=t(a,[["render",n]]);export{g as __pageData,u as default};
